+    expect(resolveGitHubCopilotBackendModelId("o5")).toBe("openai/o5");
+    expect(resolveGitHubCopilotBackendModelId("claude-sonnet-4.5")).toBe(
+      "anthropic/claude-sonnet-4.5",
