+    expect(resolveGitHubCopilotBackendModelId(" mistral-large ")).toBe("mistral-large");
+    expect(resolveGitHubCopilotBackendModelId("")).toBe("");
+    expect(resolveGitHubCopilotBackendModelId(" openai/gpt-4.1 ")).toBe("openai/gpt-4.1");
